-- Anonymized test data for MyTourbook Derby fixture.
--
-- Fixed constants (reuse these in CE-0036 tests):
--   bikeA UUID : 'a1111111-0001-0001-0001-000000000001'  (tracked bike A)
--   bikeB UUID : 'b2222222-0002-0002-0002-000000000002'  (tracked bike B)
--   bikeC UUID : 'c3333333-0003-0003-0003-000000000003'  (foreign/untracked)
--
-- TOURID scheme (contiguous, no personal data):
--   9000000000001-9000000000012  bikeA candidates (valid: person=0, type IN {0,1,2,4,113})
--   9000000000013-9000000000024  bikeB candidates (valid: person=0, type IN {0,1,2,4,113})
--   9000000000025                bikeA+bikeB tags (AMBIGUOUS_BIKE — excluded by adapter)
--   9000000000026                bikeC tag        (excluded: UUID not in :bikeUuids)
--   9000000000027                Road tag only    (excluded: non-UUID tag name)
--   9000000000028                untagged         (excluded: no join row)
--   9000000000029                bikeA, TOURPERSON_PERSONID=4 (excluded: person filter)
--   9000000000030                bikeA, TOURTYPE_TYPEID=6    (excluded: type filter)
--
-- DBVERSION=59 (current real-DB value). To test SCHEMA_DRIFT, change this value and rebuild.
-- TOURSTARTTIME is milliseconds since epoch (2025, no personal location data).



-- TOURDATA column order used below:
--   TOURID, STARTYEAR, STARTMONTH, STARTDAY, STARTHOUR, STARTMINUTE, STARTWEEK,
--   STARTDISTANCE, DISTANCE, STARTALTITUDE, STARTPULSE, DPTOLERANCE,
--   TOURDISTANCE, TOURALTUP, TOURALTDOWN, DEVICETRAVELTIME,
--   DEVICEDISTANCE, DEVICEWHEEL, DEVICEWEIGHT, DEVICETOTALUP, DEVICETOTALDOWN,
--   TOURTITLE, TOURSTARTTIME, TOURDEVICETIME_ELAPSED, TOURCOMPUTEDTIME_MOVING,
--   TOURDEVICETIME_RECORDED, POWER_TOTALWORK, TOURTYPE_TYPEID, TOURPERSON_PERSONID

